import boto3
import json

bedrock_agent = boto3.client('bedrock-agent-runtime')

def detect_retrieval_quality(session_id, agent_id, input_text):
    response = bedrock_agent.invoke_agent(
        agentId=agent_id,
        agentAliasId='latest',
        sessionId=session_id,
        inputText=input_text
    )

    relevance_scores = []
    stream = response['completion']
    for event in stream:
        if 'chunk' in event:
            chunk = event['chunk']['bytes'].decode()
            if 'retrievalInfo' in chunk:
                data = json.loads(chunk)
                if 'retrievalInfo' in data:
                    for doc in data['retrievalInfo']:
                        relevance_scores.append(doc.get('score', 0))

    avg_score = sum(relevance_scores) / len(relevance_scores) if relevance_scores else 0
    return {
        'quality_issue': avg_score < 0.75,
        'avg_relevance': avg_score,
        'document_count': len(relevance_scores)
    }

from collections import Counter

def analyze_chunk_overlap(retrieval_results):
    chunk_locations = []
    for doc in retrieval_results.get('retrievalInfo', []):
        location = doc.get('location', {}).get('type', 'unknown')
        if location == 'S3':
            chunk_locations.append(doc['location']['s3Location']['uri'])

    location_counter = Counter(chunk_locations)
    overlap_ratio = sum(count > 1 for count in location_counter.values()) / len(chunk_locations)

    return {
        'overlap_detected': overlap_ratio > 0.3,
        'overlap_ratio': overlap_ratio,
        'repeated_chunks': dict(location_counter.most_common(5))
    }

def detect_session_drift(session_history):
    all_retrieved_uris = []
    for turn in session_history[-5:]:  # Last 5 turns
        if 'retrievalInfo' in turn:
            for doc in turn['retrievalInfo']:
                uri = doc.get('location', {}).get('s3Location', {}).get('uri')
                if uri:
                    all_retrieved_uris.append(uri)

    uri_counter = Counter(all_retrieved_uris)
    repeat_ratio = sum(count > 2 for count in uri_counter.values()) / len(all_retrieved_uris)

    return {
        'context_drift': repeat_ratio > 0.4,
        'repeat_ratio': repeat_ratio,
        'stale_documents': dict(uri_counter.most_common(3))
    }

