import boto3

bedrock_agent = boto3.client('bedrock-agent')

def optimize_kb_chunking(knowledge_base_id):
    # Update knowledge base with semantic chunking
    bedrock_agent.update_knowledge_base(
        knowledgeBaseId=knowledge_base_id,
        roleArn='arn:aws:iam::ACCOUNT:role/BedrockKBRole',
        knowledgeBaseConfiguration={
            'type': 'VECTOR',
            'vectorKnowledgeBaseConfiguration': {
                'embeddingModelArn': 'arn:aws:bedrock:us-east-1::foundation-model/amazon.titan-embed-text-v1'
            }
        },
        storageConfiguration={
            'type': 'OPENSEARCH_SERVERLESS',
            'opensearchServerlessConfiguration': {
                'collectionArn': 'arn:aws:aoss:us-east-1:ACCOUNT:collection/COLLECTION',
                'vectorIndexName': 'rag_index',
                'fieldMapping': {
                    'vectorField': 'embedding',
                    'textField': 'text',
                    'metadataField': 'metadata'
                }
            }
        },
        chunkingConfiguration={
            'chunkingStrategy': 'SEMANTIC',
            'chunkSize': 300,
            'chunkOverlapPercentage': 20,
            'treatNewlineAsParagraph': True
        }
    )

def invoke_agent_with_hybrid_retrieval(session_id, agent_id, query, filters=None):
    filter_config = {
        'andAllFilters': [
            {
                'equals': {
                    'key': 'category',
                    'value': 'api-reference'
                }
            },
            {
                'range': {
                    'key': 'publish_date',
                    'gte': '2024-01-01'
                }
            }
        ] if filters else []
    }

    response = bedrock_agent_runtime.invoke_agent(
        agentId=agent_id,
        agentAliasId='latest',
        sessionId=session_id,
        inputText=query,
        enableTrace=True,
        knowledgeBaseRetrievalConfiguration={
            'knowledgeBaseIds': ['KB_ID'],
            'retrievalConfiguration': {
                'vectorSearchConfiguration': {
                    'numberOfResults': 5,
                    'overrideSearchType': 'HYBRID',
                    'filter': filter_config
                }
            }
        }
    )
    return response

